import{_ as e,o as i,c as t,a2 as a}from"./chunks/framework.jWxB9oXr.js";const g=JSON.parse('{"title":"Designing Robust Ops","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Designing Robust Ops"}],["meta",{"property":"og:description","content":"Designing Robust Ops — Silvery reference documentation with detailed API information."}],["meta",{"property":"og:url","content":"https://silvery.dev/reference/robust-ops.html"}],["link",{"rel":"canonical","href":"https://silvery.dev/reference/robust-ops.html"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://silvery.dev/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://silvery.dev/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Designing Robust Ops\\",\\"item\\":\\"https://silvery.dev/reference/robust-ops\\"}]}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Designing Robust Ops\\",\\"description\\":\\"Designing Robust Ops — Silvery reference documentation with detailed API information.\\",\\"url\\":\\"https://silvery.dev/reference/robust-ops.html\\",\\"dateModified\\":\\"2026-03-10T17:43:43.000Z\\",\\"datePublished\\":\\"2026-03-10T17:43:43.000Z\\",\\"image\\":\\"https://silvery.dev/og-image.png\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Bjørn Stabell\\",\\"url\\":\\"https://beorn.codes\\",\\"sameAs\\":[\\"https://github.com/beorn\\"]}}"]]},"headers":[],"relativePath":"reference/robust-ops.md","filePath":"reference/robust-ops.md","lastUpdated":1773164623000}'),n={name:"reference/robust-ops.md"};function r(o,s,p,d,l,h){return i(),t("div",null,[...s[0]||(s[0]=[a(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /reference/robust-ops.md for this page in Markdown format</div><h1 id="designing-robust-ops" tabindex="-1">Designing Robust Ops <a class="header-anchor" href="#designing-robust-ops" aria-label="Permalink to &quot;Designing Robust Ops&quot;">​</a></h1><p>The examples in the <a href="./../guides/terminal-apps.html">Building an App</a> Level 3 guide use index-based ops: <code>{ op: &quot;toggleDone&quot;, index: 2 }</code>. This works for single-session undo but breaks when ops need to survive reordering — undo after other edits, concurrent users, or offline sync. If someone inserts at index 1, your <code>index: 2</code> now points to the wrong item.</p><p><strong>Prefer identity-based ops</strong>: <code>{ op: &quot;toggleDone&quot;, id: &quot;abc123&quot; }</code>. This is the same principle behind CRDTs[^crdt] — operations that commute (produce the same result regardless of order) are safe for concurrent use.</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Fragile — depends on ordering</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> FragileOp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">op</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;toggleDone&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">index</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Robust — works regardless of order</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> RobustOp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">op</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;toggleDone&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Gold standard — idempotent (applying twice = applying once)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> IdempotentOp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">op</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;setDone&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">done</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> boolean</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Op style</th><th>Undo</th><th>Concurrent</th><th>Offline sync</th></tr></thead><tbody><tr><td><code>index: 2</code></td><td>Fragile</td><td>Breaks</td><td>Breaks</td></tr><tr><td><code>id: &quot;abc&quot;</code> + toggle</td><td>Works</td><td>Works</td><td>Double-toggle risk</td></tr><tr><td><code>id: &quot;abc&quot;</code> + <code>done: true</code></td><td>Works</td><td>Works</td><td>Idempotent</td></tr></tbody></table><p>You don&#39;t need to start here. Index-based is fine for simple undo. But when you add collaboration, offline sync, or AI automation — design identity-based, ideally idempotent.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./../guides/terminal-apps.html#level-3-everything-is-data">Building an App — Level 3</a> — where ops-as-data is introduced</li></ul><hr><p>[^crdt]: <a href="https://en.wikipedia.org/wiki/Conflict-free_replicated_data_type" target="_blank" rel="noreferrer">CRDTs</a> (Conflict-free Replicated Data Types) — data structures designed for distributed systems that can be edited independently on multiple replicas and merged without conflicts.</p>`,11)])])}const c=e(n,[["render",r]]);export{g as __pageData,c as default};
